import { useEffect, useState } from "react";

import axios from "axios";

import { useParams } from "react-router-dom";

function BookingPage() {

    const { id } = useParams();

    const [fromDate, setFromDate] =
        useState("");

    const [toDate, setToDate] =
        useState("");

    const [license, setLicense] =
        useState(null);

    const [totalAmount, setTotalAmount] =
        useState(0);

    

    useEffect(() => {

        if (fromDate && toDate) {

            const startDate =
                new Date(fromDate);

            const endDate =
                new Date(toDate);

            const differenceInTime =
                endDate - startDate;

            const days =
                differenceInTime /
                (1000 * 60 * 60 * 24) + 1;

            const amount =
                days * pricePerDay;

            setTotalAmount(amount);
        }

    }, [fromDate, toDate]);

    const handleBooking = () => {

        if (!fromDate) {

            alert("Please select From Date");

            return;
        }

        if (!toDate) {

            alert("Please select To Date");

            return;
        }

        if (!license) {

            alert("Please upload Driving License");

            return;
        }

        console.log(fromDate);

        console.log(toDate);

        console.log(license);

        alert("Booking Submitted Successfully");
    };

    return (

        <div
            style={{
                padding: "30px"
            }}
        >

            <h1>

                Car Booking Page

            </h1>

            <br />

            <div>

                <label>

                    From Date

                    <span
                        style={{
                            color: "red"
                        }}
                    >
                        *
                    </span>

                </label>

                <br />

                <input
                    type="date"

                    value={fromDate}

                    onChange={(e) =>
                        setFromDate(e.target.value)
                    }

                    style={{
                        padding: "10px",
                        width: "300px"
                    }}
                />

            </div>

            <br />

            <div>

                <label>

                    To Date

                    <span
                        style={{
                            color: "red"
                        }}
                    >
                        *
                    </span>

                </label>

                <br />

                <input
                    type="date"

                    value={toDate}

                    onChange={(e) =>
                        setToDate(e.target.value)
                    }

                    style={{
                        padding: "10px",
                        width: "300px"
                    }}
                />

            </div>

            <br />

            <div>

                <label>

                    Upload Driving License

                    <span
                        style={{
                            color: "red"
                        }}
                    >
                        *
                    </span>

                </label>

                <br />

                <input
                    type="file"

                    onChange={(e) =>
                        setLicense(e.target.files[0])
                    }
                />

            </div>

            <br />

            <h2>

                Total Amount : ₹ {totalAmount}

            </h2>

            <button

                onClick={handleBooking}

                style={{
                    padding: "12px",
                    backgroundColor: "black",
                    color: "white",
                    border: "none",
                    borderRadius: "5px",
                    cursor: "pointer"
                }}
            >

                Confirm Booking

            </button>

        </div>
    );
}

export default BookingPage;
